// tools.js
export const TOOLS = [
  { type: "function", function: {
      name: "get_weather",
      description: "Get the current weather for a city",
      parameters: { type: "object", properties: {
          city: { type: "string", description: "City name, e.g. Paris" } },
        required: ["city"] } } },
  { type: "function", function: {
      name: "calculator",
      description: "Evaluate a basic arithmetic expression",
      parameters: { type: "object", properties: {
          expression: { type: "string", description: "e.g. 23 * 7 + 1" } },
        required: ["expression"] } } },
];

export const FUNCS = {
  get_weather: ({ city }) => `18 C and cloudy in ${city}`, // fake data
  calculator: ({ expression }) => String(Function(`"use strict"; return (${expression})`)()), // demo only
};

// round_trip.js
import OpenAI from "openai";
import { TOOLS, FUNCS } from "./tools.js";

const client = new OpenAI();
const messages = [{ role: "user",
  content: "What's the weather in Paris, and what is 23 * 7?" }];

let resp = await client.chat.completions.create({
  model: "gpt-5-mini", messages, tools: TOOLS });
let msg = resp.choices[0].message;

while (msg.tool_calls?.length) {
  messages.push(msg); // keep the assistant turn with its tool_calls
  for (const call of msg.tool_calls) {
    const args = JSON.parse(call.function.arguments);
    const result = FUNCS[call.function.name](args);
    console.log(`-> ${call.function.name}(${call.function.arguments}) = ${result}`);
    messages.push({ role: "tool", tool_call_id: call.id, content: result });
  }
  resp = await client.chat.completions.create({
    model: "gpt-5-mini", messages, tools: TOOLS });
  msg = resp.choices[0].message;
}

console.log("\nFinal answer:", msg.content);

