// safe_extract.js
import OpenAI, { LengthFinishReasonError } from "openai";

const client = new OpenAI();

async function extract(text) {
  try {
    const completion = await client.chat.completions.parse({
      model: "gpt-5-mini",
      messages: [
        { role: "system", content: "Extract invoice data." },
        { role: "user", content: text },
      ],
      response_format: zodResponseFormat(Invoice, "invoice"),
      max_completion_tokens: 5000,
    });
    const msg = completion.choices[0].message;
    if (msg.refusal) {
      console.log("Model refused:", msg.refusal);
      return null;
    }
    return msg.parsed;
  } catch (err) {
    if (err instanceof LengthFinishReasonError) {
      console.log("Truncated before valid JSON -- raise max_completion_tokens");
      return null;
    }
    throw err;
  }
}

console.log(await extract("ACME, $50 USD for stickers, due 2026-07-01"));

// cache_demo.js
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();
// repeat to clear the ~2048-token minimum cacheable prefix on sonnet-4-6
const longDoc = ("MCP is an open protocol that standardizes how AI applications " +
  "connect to external tools and data sources. ").repeat(300);

async function ask(question) {
  const resp = await client.messages.create({
    model: "claude-sonnet-4-6",
    max_tokens: 256,
    system: [{
      type: "text",
      text: "Answer questions about this document:\n" + longDoc,
      cache_control: { type: "ephemeral" },
    }],
    messages: [{ role: "user", content: question }],
  });
  const u = resp.usage;
  console.log(`cache_creation=${u.cache_creation_input_tokens}  ` +
    `cache_read=${u.cache_read_input_tokens}  input=${u.input_tokens}`);
}

await ask("What is MCP?"); // call 1: cache_creation > 0, cache_read = 0
await ask("What is MCP?"); // call 2: cache_creation = 0, cache_read > 0

// cache_buster.js -- same as cache_demo.js, but with one bad line
async function ask(question) {
  const resp = await client.messages.create({
    model: "claude-sonnet-4-6",
    max_tokens: 256,
    system: [{
      type: "text",
      // BUG: changes every call, so the prefix never matches
      text: `Current time: ${Date.now()}\n` + longDoc,
      cache_control: { type: "ephemeral" },
    }],
    messages: [{ role: "user", content: question }],
  });
  const u = resp.usage;
  console.log(`cache_creation=${u.cache_creation_input_tokens}  ` +
    `cache_read=${u.cache_read_input_tokens}`);
}

await ask("What is MCP?"); // cache write
await ask("What is MCP?"); // ANOTHER cache write -- read stays 0. Money on fire.

// stream_openai.js
import OpenAI from "openai";

const client = new OpenAI();
const start = performance.now();
let first = null;

const stream = await client.chat.completions.create({
  model: "gpt-5-mini",
  messages: [{ role: "user",
    content: "Write a 200-word story about a robot barista." }],
  stream: true,
});
for await (const chunk of stream) {
  const delta = chunk.choices[0]?.delta?.content;
  if (delta) {
    if (first === null) first = (performance.now() - start) / 1000;
    process.stdout.write(delta);
  }
}

const total = (performance.now() - start) / 1000;
console.log(`\n\nTTFT: ${first.toFixed(2)}s | total: ${total.toFixed(2)}s`);

// stream_anthropic.js
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic();
const start = performance.now();
let first = null;

const stream = client.messages.stream({
  model: "claude-sonnet-4-6",
  max_tokens: 1024,
  messages: [{ role: "user",
    content: "Write a 200-word story about a robot barista." }],
});
stream.on("text", (text) => {
  if (first === null) first = (performance.now() - start) / 1000;
  process.stdout.write(text);
});
const final = await stream.finalMessage();

const total = (performance.now() - start) / 1000;
console.log(`\n\nTTFT: ${first.toFixed(2)}s | total: ${total.toFixed(2)}s ` +
  `| output tokens: ${final.usage.output_tokens}`);

